#ifdef ENABLE_DP
#pragma OPENCL EXTENSION cl_khr_fp64 : enable
#endif

#ifdef ENABLE_HP
#pragma OPENCL EXTENSION cl_khr_fp16 : enable
#endif

#ifndef ELEMENTS_PER_THREAD
#define ELEMENTS_PER_THREAD 1
#endif

#ifndef FUSION_DEGREE
#define FUSION_DEGREE 1
#endif

__kernel void benchmark_func(class_T seed, __global class_T* data) {
  const size_t lid = get_local_id(0);
  const size_t gid = get_global_id(0);
  const size_t gsize = get_global_size(0);

#ifdef BLOCK_STRIDED
  const size_t stride = (size_t)blockdim;
  const size_t base =
      get_group_id(0) * (size_t)blockdim * (size_t)ELEMENTS_PER_THREAD *
          (size_t)FUSION_DEGREE +
      lid;
#else
  const size_t stride = gsize;
  const size_t base = gid;
#endif

  for (uint f = 0; f < (uint)FUSION_DEGREE; ++f) {
    size_t idx = base + (size_t)f * (size_t)ELEMENTS_PER_THREAD * stride;

    for (uint e = 0; e < (uint)ELEMENTS_PER_THREAD; ++e) {
      class_T t = data[idx];

      for (uint j = 0; j < (uint)COMPUTE_ITERATIONS; ++j) {
        t = t * t + seed;
      }

      data[idx] = t;
      idx += stride;
    }
  }
}
